  # Render a Lucide icon inline. size in px; pass extra Tailwind classes via css.
  def lucide(name, size: 18, stroke_width: 2, css: nil, color: nil)
    paths = LUCIDE_PATHS[name.to_s]
    return "".html_safe unless paths

    styles = "width:#{size}px;height:#{size}px;flex-shrink:0;"
    styles += "color:#{color};" if color
    classes = [ "inline-flex align-middle", css ].compact.join(" ")

    %(<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="#{stroke_width}" stroke-linecap="round" stroke-linejoin="round" class="#{classes}" style="#{styles}" aria-hidden="true">#{paths}</svg>).html_safe
  end
